import{_ as t,o as l,c as e,a7 as i}from"./chunks/framework.C5fSpjcB.js";const g=JSON.parse('{"title":"デッキ構築ガイド","description":"","frontmatter":{},"headers":[],"relativePath":"ja/cards/deckbuilding.md","filePath":"ja/cards/deckbuilding.md","lastUpdated":1775394001000}'),r={name:"ja/cards/deckbuilding.md"};function n(s,a,o,d,h,c){return l(),e("div",null,[...a[0]||(a[0]=[i('<h1 id="デッキ構築ガイド" tabindex="-1">デッキ構築ガイド <a class="header-anchor" href="#デッキ構築ガイド" aria-label="Permalink to &quot;デッキ構築ガイド&quot;">​</a></h1><p>忘却前夜のデッキ構築の基本とコツを解説します。ローグライト×デッキ構築の醍醐味を楽しみましょう。</p><h2 id="デッキ構築の基本" tabindex="-1">デッキ構築の基本 <a class="header-anchor" href="#デッキ構築の基本" aria-label="Permalink to &quot;デッキ構築の基本&quot;">​</a></h2><h3 id="通常戦闘-ストーリー・ステージ" tabindex="-1">通常戦闘（ストーリー・ステージ） <a class="header-anchor" href="#通常戦闘-ストーリー・ステージ" aria-label="Permalink to &quot;通常戦闘（ストーリー・ステージ）&quot;">​</a></h3><p>通常の戦闘では、覚醒体の固有カードセットがそのままデッキとなります。カード強化とレベリングによりデッキ性能が向上します。</p><h3 id="調査行動-investigation" tabindex="-1">調査行動（Investigation） <a class="header-anchor" href="#調査行動-investigation" aria-label="Permalink to &quot;調査行動（Investigation）&quot;">​</a></h3><p>ローグライトモードでは、ランの中でカードを取得・除去してデッキを構築します。</p><ul><li>戦闘報酬やイベントでカードを追加</li><li>不要なカードはショップで除去可能</li><li>ラン終了時にデッキはリセットされる</li></ul><h2 id="算力管理" tabindex="-1">算力管理 <a class="header-anchor" href="#算力管理" aria-label="Permalink to &quot;算力管理&quot;">​</a></h2><p>毎ターンの算力は<strong>5</strong>です。デッキ構築では算力効率を常に意識しましょう。</p><table tabindex="0"><thead><tr><th style="text-align:center;">コスト帯</th><th style="text-align:center;">推奨枚数（割合）</th><th style="text-align:left;">備考</th></tr></thead><tbody><tr><td style="text-align:center;">0コスト</td><td style="text-align:center;">2〜3枚</td><td style="text-align:left;">算力不要だが効果は控えめ</td></tr><tr><td style="text-align:center;">1〜2コスト</td><td style="text-align:center;">デッキの50〜60%</td><td style="text-align:left;">主力。使いやすく回転率が高い</td></tr><tr><td style="text-align:center;">3コスト</td><td style="text-align:center;">デッキの20〜30%</td><td style="text-align:left;">中核カード。ターンの軸</td></tr><tr><td style="text-align:center;">4〜5コスト</td><td style="text-align:center;">2〜4枚</td><td style="text-align:left;">強力だが算力を圧迫する</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>デッキが厚くなりすぎると主力カードのドロー率が下がります。調査行動では「カード追加」より「カード除去」の方が重要な場面も多いです。</p></div><h2 id="界域別デッキの特徴" tabindex="-1">界域別デッキの特徴 <a class="header-anchor" href="#界域別デッキの特徴" aria-label="Permalink to &quot;界域別デッキの特徴&quot;">​</a></h2><h3 id="混沌デッキ" tabindex="-1"><span class="realm-badge realm-chaos">混沌</span>デッキ <a class="header-anchor" href="#混沌デッキ" aria-label="Permalink to &quot;&lt;span class=&quot;realm-badge realm-chaos&quot;&gt;混沌&lt;/span&gt;デッキ&quot;">​</a></h3><ul><li>狂気蓄積を加速するカードを軸に構築</li><li>バーストの回転率を重視</li><li>低〜中コストカード中心で手数を増やす</li></ul><h3 id="深海デッキ" tabindex="-1"><span class="realm-badge realm-aequor">深海</span>デッキ <a class="header-anchor" href="#深海デッキ" aria-label="Permalink to &quot;&lt;span class=&quot;realm-badge realm-aequor&quot;&gt;深海&lt;/span&gt;デッキ&quot;">​</a></h3><ul><li>シールド・回復カードで耐久しつつ戦う</li><li>敵のデバフを重ねて有利状況を作る</li><li>中コストカード中心のバランス型</li></ul><h3 id="血肉デッキ" tabindex="-1"><span class="realm-badge realm-caro">血肉</span>デッキ <a class="header-anchor" href="#血肉デッキ" aria-label="Permalink to &quot;&lt;span class=&quot;realm-badge realm-caro&quot;&gt;血肉&lt;/span&gt;デッキ&quot;">​</a></h3><ul><li>自傷カードで血肉固有バフを蓄積</li><li>HPが低いほど火力が上がるギミックを活用</li><li>ハイリスク・ハイリターンな構成</li></ul><h3 id="超維デッキ" tabindex="-1"><span class="realm-badge realm-ultra">超維</span>デッキ <a class="header-anchor" href="#超維デッキ" aria-label="Permalink to &quot;&lt;span class=&quot;realm-badge realm-ultra&quot;&gt;超維&lt;/span&gt;デッキ&quot;">​</a></h3><ul><li>ドロー加速・算力回復カードで大量展開</li><li>カードコンボを繋げるテクニカルなプレイ</li><li>高コストカードもドロー力でカバー</li></ul><h2 id="デッキ構築のコツ" tabindex="-1">デッキ構築のコツ <a class="header-anchor" href="#デッキ構築のコツ" aria-label="Permalink to &quot;デッキ構築のコツ&quot;">​</a></h2><ol><li><strong>軸を決める</strong> — 勝ち筋を1つ明確にする</li><li><strong>薄いデッキが強い</strong> — 不要カードは積極的に除去</li><li><strong>シナジーを意識する</strong> — 相性の良いカード同士を採用</li><li><strong>算力カーブを意識する</strong> — 毎ターン5算力を使い切れる構成に</li><li><strong>対策カードを忘れない</strong> — 回復・防御カードも最低限は必要</li></ol><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./">カードシステム概要</a></li><li><a href="./list.html">カード一覧</a></li><li><a href="./../modes/combat.html">戦闘システム</a></li><li><a href="./../modes/investigation.html">調査行動</a></li><li><a href="./../awakeners/team-building.html">編成ガイド</a></li></ul>',25)])])}const m=t(r,[["render",n]]);export{g as __pageData,m as default};
